import React, { useState, useEffect } from 'react';
import { useBlockchain } from '../context/BlockchainContext';
import { ethers } from 'ethers';

const UserDashboard: React.FC = () => {
    const { account, contract } = useBlockchain();
    const [name, setName] = useState('');
    const [documentData, setDocumentData] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [userDetails, setUserDetails] = useState<any>(null);

    useEffect(() => {
        if (contract && account) {
            fetchUserDetails();
        }
    }, [contract, account]);

    const fetchUserDetails = async () => {
        if (!contract || !account) return;
        try {
            const details = await contract.getUserDetails(account);
            if (details[0] !== '') { // If name is not empty, user is registered
                setUserDetails({
                    name: details[0],
                    documentHash: details[1],
                    isVerified: details[2],
                    verifiedAt: Number(details[3]),
                    verifiedBy: details[4]
                });
            } else {
                setUserDetails(null);
            }
        } catch (error) {
            console.error("Error fetching user details:", error);
        }
    };

    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !name || !documentData) return;

        setLoading(true);
        setMessage('');
        try {
            // Generate simple hash from document string data
            const docHash = ethers.id(documentData); // keccak256 hash

            const tx = await contract.registerUser(name, docHash);
            await tx.wait();

            setMessage(`Successfully registered! Your calculated doc hash is: ${docHash}`);
            await fetchUserDetails();
        } catch (error: any) {
            setMessage(`Error registering: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    if (!account) {
        return <div style={{ padding: '2rem', textAlign: 'center' }}>Please connect your wallet to view your dashboard.</div>;
    }

    return (
        <div style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
            <h2>User Dashboard</h2>
            <p>Welcome, {account}</p>

            {message && (
                <div style={{ padding: '1rem', marginTop: '1rem', backgroundColor: message.includes('Error') ? '#ffebee' : '#e8f5e9', borderRadius: '4px', wordBreak: 'break-all' }}>
                    {message}
                </div>
            )}

            {userDetails ? (
                <div style={{ padding: '1.5rem', border: '1px solid #2196f3', borderRadius: '8px', marginTop: '2rem', backgroundColor: '#e3f2fd' }}>
                    <h3>Your KYC Profile</h3>
                    <ul style={{ listStyleType: 'none', padding: 0, lineHeight: '2' }}>
                        <li><strong>Name:</strong> {userDetails.name}</li>
                        <li><strong>Document Hash:</strong> <span style={{ fontFamily: 'monospace', fontSize: '0.9em' }}>{userDetails.documentHash}</span></li>
                        <li>
                            <strong>Status:</strong> 
                            {userDetails.isVerified ? 
                                <span style={{ color: 'green', fontWeight: 'bold', marginLeft: '0.5rem' }}>VERIFIED ✓</span> : 
                                <span style={{ color: 'orange', fontWeight: 'bold', marginLeft: '0.5rem' }}>PENDING VERIFICATION</span>
                            }
                        </li>
                        {userDetails.isVerified && (
                            <>
                                <li><strong>Verified By:</strong> {userDetails.verifiedBy}</li>
                                <li><strong>Verified At:</strong> {new Date(userDetails.verifiedAt * 1000).toLocaleString()}</li>
                            </>
                        )}
                    </ul>
                </div>
            ) : (
                <div style={{ padding: '1.5rem', border: '1px solid #ccc', borderRadius: '8px', marginTop: '2rem' }}>
                    <h3>Register for KYC</h3>
                    <p>Submit your details and document data to generate a hash on the blockchain.</p>

                    <form onSubmit={handleRegister} style={{ display: 'flex', flexDirection: 'column', gap: '1rem', marginTop: '1rem' }}>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.5rem' }}>Full Name:</label>
                            <input 
                                type="text" 
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="Enter your full legal name"
                                style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
                                required
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.5rem' }}>Document Identifier (e.g., Passport Number / SSN):</label>
                            <input 
                                type="text" 
                                value={documentData}
                                onChange={(e) => setDocumentData(e.target.value)}
                                placeholder="This will be hashed securely before submission"
                                style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
                                required
                            />
                            <small style={{ color: '#666', marginTop: '0.25rem', display: 'block' }}>We use Keccak256 algorithm to hash this data locally. Only the hash is sent to the blockchain.</small>
                        </div>

                        <button 
                            type="submit" 
                            disabled={loading || !name || !documentData}
                            style={{ padding: '0.75rem', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px', cursor: (loading || !name || !documentData) ? 'not-allowed' : 'pointer', marginTop: '1rem' }}
                        >
                            {loading ? 'Processing...' : 'Register and Hash Document'}
                        </button>
                    </form>
                </div>
            )}
        </div>
    );
};

export default UserDashboard;
